using System;
using System.IO;

namespace HDLG.Tests
{
    internal static class PdfSetup
    {
        private static bool _initialized = false;
        private static readonly object _lock = new();

        public static void CreatePdfDocs()
        {
            if (_initialized) return;
            lock (_lock)
            {
                if (_initialized) return;

                string validPdfBase64 = "";
                string emptyPdfBase64 = "";
                string encryptedPdfBase64 = "";
                string invalidPdfBase64 = "aW52YWxpZCBkYXRh";

                File.WriteAllBytes("test.pdf", Convert.FromBase64String(validPdfBase64));
                File.WriteAllBytes("test_empty_title.pdf", Convert.FromBase64String(emptyPdfBase64));
                File.WriteAllBytes("test_encrypted.pdf", Convert.FromBase64String(encryptedPdfBase64));
                File.WriteAllBytes("test_invalid.pdf", Convert.FromBase64String(invalidPdfBase64));

                _initialized = true;
            }
        }

        public static void Cleanup()
        {
            // Do not delete files during parallel test execution to prevent race conditions.
            // These temporary files will be cleaned up by the build/clean system.
        }
    }
}
